VALUES
  ('disabled-8b44517b-moex-00104', 'disabled-8b44517b', 'disabled-8b44517b-moex-113-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '下列何者非行政罰？', '["甲為證券商之總經理，因違反證券交易法，遭主管機關解除其經理人職務", "乙因違反道路交通管理處罰條例，遭主管機關處以罰鍰", "丙無正當理由，攜帶具殺傷力之器械，因違反社會秩序維護法，遭主管 機關沒入其器械", "丁為學校教師，因體罰學生，違反兒童及少年福利與權益保障法規定， 遭主管機關公布其姓名 30830"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00105', 'disabled-8b44517b', 'disabled-8b44517b-moex-113-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '關於行政執行聲明異議之敘述，下列何者錯誤？', '["對具行政處分性質之執行命令不服，經依行政執行法之聲明異議程序， 聲明異議人可直接提起撤銷訴訟", "受理機關認為聲明異議無理由者，應予以駁回", "不服中央各院之行政執行而聲明異議，由中央各院自行受理異議並為 決定", "受理機關認為聲明異議有理由者，應即停止執行，並撤銷或更正已為之 執行行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00106', 'disabled-8b44517b', 'disabled-8b44517b-moex-113-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '關於政府資訊公開法之敘述，下列何者錯誤？', '["係以保障人民知的權利，增進人民對公共事務之瞭解、信賴及監督為 目的", "依該法規定，公開之對象為一般人民", "申請人依該法規定申請行政機關提供行政資訊遭拒絕者，如有不服，僅 得於對實體決定聲明不服時，一併聲明之", "依該法規定申請行政機關提供行政資訊之權利，屬實體權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00107', 'disabled-8b44517b', 'disabled-8b44517b-moex-113-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '土地所有權人甲於1月3日收到新北市政府工務局所開立「申請建築執照 補件通知單」，通知其應於30日內依建築法規定補件，但甲不服並於3月 3日提起訴願。下列何者正確？', '["該補件通知單之性質為觀念通知", "甲提起之訴願已逾訴願期間，訴願管轄機關應以無理由駁回甲之訴願", "甲不服該補件通知單，應向內政部提起訴願", "該補件通知單具有強制效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00108', 'disabled-8b44517b', 'disabled-8b44517b-moex-113-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '甲在河流旁搭建工寮並開闢菜園，經主管機關認定妨害水土保持屬於違 法，命甲限期回復原狀。甲不服，除循序提起訴願救濟外，得以下列何種 程序在救濟進行期間實現暫時權利保護？', '["應向行政法院聲請定暫時狀態假處分，由法院裁定該工寮及菜園暫時為 合法", "應向行政法院聲請保全處分，保全工寮及菜園之事實狀態", "應依據行政執行法向主管機關聲明異議", "應依行政訴訟法或訴願法聲請暫時停止執行該命回復原狀之處分 30830"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00109', 'disabled-8b44517b', 'disabled-8b44517b-moex-113-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '下列何者非屬確認行政處分無效之訴的實體判決要件？', '["確認對象須為行政處分之無效", "須已向原處分機關請求確認其無效未被允許或不為確答", "須經訴願程序而遭駁回", "須有即受確認判決之法律上利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00110', 'disabled-8b44517b', 'disabled-8b44517b-moex-113-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '關於行政訴訟制度之敘述，下列何者正確？', '["收容聲請事件適用以原就被之原則", "對於已執行而無回復原狀可能之行政處分，得提起確認該行政處分無效 之訴訟", "確認行政處分無效之訴訟，須已向原處分機關請求確認其無效未被允 許，或經請求後於30日內不為確答者，始得提起之", "受交通違規裁罰處分，應先經訴願程序，始得提起行政訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00111', 'disabled-8b44517b', 'disabled-8b44517b-moex-113-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '關於國家賠償法所規定之公共設施國家賠償責任，下列何者正確？', '["當公共設施已委託民間團體或個人管理時，國家即免除損害賠償責任", "於開放之山域、水域等自然公物，經管理機關、受委託管理之民間團體 或個人已就使用該公物為適當之警告或標示，而人民仍從事冒險或具危 險性活動，國家不負損害賠償責任", "於開放之山域、水域等自然公物內之設施，經管理機關、受委託管理之 民間團體或個人已就使用該公物為適當之警告或標示，而人民仍從事冒 險或具危險性活動，國家不負損害賠償責任", "就公共設施設置或管理之瑕疵應負責之第三人，賠償機關對之並無求 償權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00112', 'disabled-8b44517b', 'disabled-8b44517b-moex-113-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '關於行政損失補償之敘述，下列何者錯誤？', '["錯誤施打疫苗造成人民身體健康受損，基於準徵收法理應予補償", "對於犯罪被害人所為之補償，非基於特別犧牲", "土地徵收為合法、有目的性對人民財產權之侵害，故須給予補償", "為防止公益重大危害而廢止授益處分時，受益人得請求信賴利益損失 補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00001', 'disabled-acfc4025', 'disabled-acfc4025-moex-113-156cbda0', 'sub-disabled-acfc4025-01', NULL, 'single_choice', '關於VLIW（VeryLongInstructionWord）處理器的敘述，下列何者錯誤？', '["其設計策略是要開發指令階層平行度（instructionlevelparallelism），每 個時脈週期可同時執行多個運算（operation）", "可透過softwarepipelining編譯技術增加迴圈（loop）程式的執行效率", "具備硬體機制偵測運算間的資料相依性，並於程式執行時自動發掘可平 行執行的運算", "可透過tracescheduling編譯器指令排程技術提高程式執行效率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5de56163c9d1", "answer_pdf_sha1": "ab19b9b1ea4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "413", "s": "1412", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL)
